-- ============================================================
-- LIMPIAR Y REINSERTAR MATERIAL ELÉCTRICO EN ORDEN CORRECTO
-- Pega este SQL en el Editor SQL de Supabase y dale Run
-- ============================================================

-- 1. Borrar todo Material Eléctrico existente
DELETE FROM refacciones WHERE categoria = 'MATERIAL ELÉCTRICO';

-- 2. Reinsertar en orden exacto del Excel con timestamps escalonados

SELECT 'Material Eléctrico reinsertado: ' || COUNT(*) || ' items' FROM refacciones WHERE categoria = 'MATERIAL ELÉCTRICO';
